export type Cell = [number, number];

const key = (x: number, y: number): string => `${x},${y}`;

const neighbors = (x: number, y: number): Cell[] => [
  [x-1,y-1],[x,y-1],[x+1,y-1],
  [x-1,y],          [x+1,y],
  [x-1,y+1],[x,y+1],[x+1,y+1],
];

const step = (cells: Cell[]): Cell[] => {
  const alive = new Set(cells.map(([x,y]) => key(x,y)));
  const neighborCount = new Map<string, number>();

  for (const [x, y] of cells) {
    for (const [nx, ny] of neighbors(x, y)) {
      const k = key(nx, ny);
      neighborCount.set(k, (neighborCount.get(k) ?? 0) + 1);
    }
  }

  const next: Cell[] = [];
  for (const [k, count] of neighborCount) {
    const [x, y] = k.split(",").map(Number) as Cell;
    if (count === 3 || (count === 2 && alive.has(k))) {
      next.push([x, y]);
    }
  }
  return next;
};

export const nextGeneration = (cells: Cell[], steps: number): Cell[] => {
  if (steps === 0) return cells;
  let current = cells;
  for (let i = 0; i < steps; i++) current = step(current);
  return current;
};

